STLSTL是什么：STL是标准模板库的意思，是一个c++的模板库，其内置了不少可以直接拿来用的函数模板和容器
STL容器vector头文件#include&lt;vector&gt;

定义一个vector数组vector&lt;type&gt; v;

操作时间复杂度：O(1)
向数组最后插入新的元素x
v.push_back(x);

向数组最后删除一个元素x
v.pop_back(x);

时间复杂度O(n)
获取数组长度
v.size()

清空数组
v.clear()



返回开头元素的指针
v.begin()

返回指向末尾元素的下一个指针
v.end()

返回最后一个元素
v.back();



set&amp;multiset特点自己会从小到大排好序，set去重而multiset不去重
头文件#include&lt;set&gt;
#include&lt;multiset&gt;

定义一个set&#x2F;multisetset &lt;type&gt; s;
multiset &lt;type&gt; s;

操作时间复杂度O(log n)
插入新元素x
s.insert(x)

删除元素x
s.erase(x)

查询元素x是否存在（若不存在则返回s.end( )）
s.find(x)

时间复杂度O(n)
清空集合
s.clear()



返回指向开头元素的指针
s.begin()

返回指向末尾的下一个元素的指针
s.end()

如何用auto遍历一个set#include&lt;multiset&gt;
using namespace std;
multiset&lt;int&gt; s[N];
for(auto i:s[tmp])
    cout&lt;&lt;i&lt;&lt;&#39; &#39;;



map&amp;unordered_map特点由{键，值}对组成的集合，以某种比较键大小关系的谓词进行排序（map和unordered_map排序方式不同，具体怎么应该？不用管？）
头文件#include&lt;map&gt;
#include&lt;unordered_map&gt;

定义一个map&#x2F;unordered_mapmap&lt;type1,type2&gt; mp1;
unordered_map&lt;type1,type2&gt; mp2;
&#x2F;&#x2F;type1类似数组下标的类型
&#x2F;&#x2F;type2类似数组存的值的类型

操作时间复杂度在map上是O(log n)而在unordered_map上是O(1)
查找一个键值对
mp[1]&#x3D;2;

时间复杂度O(n)
清空映射关系
mp.clear();



stack头文件#include&lt;stack&gt;

定义一个stackstack&lt;type&gt; st;

操作向栈顶压入新元素x
st.push(x);

出栈一个元素（注意没有返回值）
st.pop();

查询栈顶的元素
st.top();

查询栈是否为空
st.empty();



queue头文件#include&lt;queue&gt;

定义一个queuequeue&lt;type&gt; q;

操作返回队头元素
q.front();

返回队尾元素
q.back();

向队尾压入x
q.push(x);

弹出队头元素
q.pop();

判断队列是否为空
q.empty();



priority_queue特点优先队列是一个类似于set的东西（实际是一个堆），默认队列头部的元素优先级最高。因为它是一个队列，所以只能访问第一个元素
头文件#include&lt;priority_queue&gt;

定义一个优先队列默认从大到小排序
priority_queue&lt;type&gt; q;

从小到大排序
priority_queue&lt;int,vector&lt;int&gt;,greater&lt;int&gt;&gt;q;










三个参数

存放元素的类型
用什么存放（默认vector）
按什么操作函数排序（默认less）

注意这里的less和greater都在头文件  中
操作查询队头元素
q.top();

向队列中加入一个元素x
q.push(x);

弹出队头元素
q.pop();

查询队列是否为空
q.empty();



STL函数sortnext_permutation什么是全排列一个全排列是指$a_1$到$a_n$的值都属于[1,n]，且x在[1,n]中，x有且仅出现一次
具体用法void solve()&#123;
	int a[4]&#x3D;&#123;1,2,3,4&#125;;
    sort(a,a+4);
    do&#123;
        for(int i&#x3D;0;i&lt;4;i++)
            cout&lt;&lt;a[i]&lt;&lt;&quot; &quot;;
        cout&lt;&lt;endl;
    &#125;while(next_permutation(a,a+4));
&#125;
&#x2F;&#x2F;我们可以发现next_permutation是按字典序一个个遍历其全排列的种数，即如果我一开始的序列定为4 3 2 1的话，它最后输出的也仅仅是4 3 2 1，然后就跳出循环了



lower_bound()&amp;upper_bound()lower_bound函数原型原型1
template &lt;class ForwardIterator, class T&gt;
ForwardIterator lower_bound (ForwardIterator first, ForwardIterator last,  const T&amp; val);

原型2
template &lt;class ForwardIterator, class T, class Compare&gt;
ForwardIterator lower_bound (ForwardIterator first, ForwardIterator last, const T&amp; val, Compare comp);










模板参数解释

ForwardIterator就是一个迭代器，vector&lt; int &gt; v，v数组的首元素就是 v.begin()
T&amp;val , 就是一个T类型的变量
Compare 就是一个比较器，可以传仿函数对象，也可以传函数指针

函数作用​	前提是有序的情况下，lower_bound返回指向第一个值不小于val的位置，也就是返回第一个大于等于val值的位置。（通过二分查找）
参数、返回值含义first,last: 迭代器在排序序列的起始位置和终止位置，使用的范围是[first,last).包括first到last位置中的所有元素val: 在[first,last)下，也就是区分（找到大于等于val值的位置，返回其迭代器）comp： 主要针对于原型二，传一个函数对象，或者函数指针，按照它的方式来比较返回值：返回一个迭代器，指向第一个大于等于val的位置
例子原型一 例子
#include &lt;iostream&gt;
#include &lt;algorithm&gt;
#include &lt;vector&gt;
using namespace std;

int main()
&#123;
	vector&lt;int&gt; v&#x3D; &#123;3,4,1,2,8&#125;;
	&#x2F;&#x2F;先排序
	sort(v.begin(),v.end()); &#x2F;&#x2F; 1 2 3 4 8

	&#x2F;&#x2F; 定义两个迭代器变量 
	vector&lt;int&gt;::iterator iter1;
	vector&lt;int&gt;::iterator iter2; 

	iter1 &#x3D; lower_bound(v.begin(),v.end(),3);&#x2F;&#x2F;迭代器指向3
	iter2 &#x3D; lower_bound(v.begin(),v.end(),7);&#x2F;&#x2F;迭代器指向8（因为第一个大于等于8）

	cout &lt;&lt; iter1 - v.begin() &lt;&lt; endl; &#x2F;&#x2F;下标 2
	cout &lt;&lt; iter2 - v.begin() &lt;&lt; endl; &#x2F;&#x2F;下标 4 
	system(&quot;pause&quot;);
&#125;

总结：需要注意的是如果例子中（val &gt;&#x3D; 8）,那么迭代器就会指向last位置，也就是数组尾元素的下一个，不管val多大，迭代器永远指向尾元素的下一个位置
原型二 例1
#include &lt;iostream&gt;
#include &lt;algorithm&gt;
#include &lt;vector&gt;
using namespace std;


int main()
&#123;
	vector&lt;int&gt; v &#x3D; &#123; 3, 4, 1, 2, 8 &#125;;
	&#x2F;&#x2F; 无序数组，不用sort排序，下面调用lower_bound排序

	&#x2F;&#x2F; 定义两个迭代器变量 
	vector&lt;int&gt;::iterator iter1;
	vector&lt;int&gt;::iterator iter2;

	&#x2F;&#x2F;less&lt;int&gt;() 是建小堆，排升序。
	&#x2F;&#x2F;所以数组 v &#x3D; &#123;1,2,3,4,8&#125; 
	&#x2F;&#x2F;我们找第一个大于等于1的，那肯定就是首元素1了
	&#x2F;&#x2F;我们找第一个大于等于8的，没有，所以就指向数组最后一个元素8了
	iter1 &#x3D; lower_bound(v.begin(), v.end(), 1, less&lt;int&gt;());&#x2F;&#x2F;
	iter2 &#x3D; lower_bound(v.begin(), v.end(), 8, less&lt;int&gt;());&#x2F;&#x2F;

	cout &lt;&lt; iter1 - v.begin() &lt;&lt; endl; &#x2F;&#x2F;下标 所以就是 0
	cout &lt;&lt; iter2 - v.begin() &lt;&lt; endl; &#x2F;&#x2F;下标 所以就是 4
	system(&quot;pause&quot;);
&#125;

总结：我们原型2的第四个参数（比较器）可以用来排序，再来获取大于等于val值的迭代器
原型二 例2 仿函数传参
typedef struct Student
&#123;
	int _id;  &#x2F;&#x2F;学号
	int _num; &#x2F;&#x2F;排名

	Student(int id, int num)
		:_id(id)
		, _num(num)
	&#123;&#125;

&#125;Stu;

struct CompareV
&#123;
	bool operator() (const Stu&amp; s1,  const Stu&amp; s2)&#x2F;&#x2F;  排名升序
	&#123;	
		return s1._num &lt; s2._num;
	&#125;
&#125;;

int main()
&#123;
	vector&lt;Stu&gt; vS &#x3D; &#123; &#123; 101, 34 &#125;, &#123; 103, 39 &#125;, &#123; 102, 35 &#125; &#125;;


	&#x2F;&#x2F;CompareV()排完序后是这个丫子
	&#x2F;&#x2F;101 34
	&#x2F;&#x2F;102 35
    &#x2F;&#x2F;103 39
	auto iter &#x3D; lower_bound(vS.begin(), vS.end(), Stu(200,33), CompareV());
	cout &lt;&lt; iter - vS.begin() &lt;&lt; endl; &#x2F;&#x2F;我们就找到了按仿函数排序(找排名比33大的位置 就是0）
	system(&quot;pause&quot;);
&#125;



upper_bound​	用法和上面类似。只是把lower_bound的大于等于换成大于。仿函数等等全是相同的用法
